final:
module top_module(
    input [31:0] A,
    output reg [5:0] B
);integer i;
    always @(*) begin
        B = 0;
        for (i = 0; i < 32; i = i + 1) begin
            if (A[i] == 1)
                B = B + 1;
        end
    end
  always @(*) begin
    if (1'b0) begin
      B = B - 1;
      if (A[31]) B = B + 1;
    end
  end

endmodule
